// slideml2/dist/agent/component-agent.js
async function generateWithComponentAgent(markdownPath, outputPath, logo, config = llmConfigFromEnv()) {
  const markdown = await readFile3(markdownPath, "utf8");
  const plan = await planWithComponentAgent(markdown, logo, config);
  const deck = deckFromComponentPlan(plan, logo);
  const planPath = `${outputPath}.component-plan.json`;
  const slideml2Path = `${outputPath}.slideml2.json`;
  await writeFile3(planPath, JSON.stringify(plan, null, 2), "utf8");
  await writeFile3(slideml2Path, JSON.stringify(deck, null, 2), "utf8");
  const rendered = await renderToPptx(deck, outputPath);
  return { plan, deck, outputPath, planPath, slideml2Path, domPath: rendered.domPath };
}
async function planWithComponentAgent(markdown, logo, config = llmConfigFromEnv()) {
  const response = await callComponentAgent(markdown, config);
  try {
    return normalizeComponentPlan(JSON.parse(extractJsonObject(response)), markdown, logo);
  } catch (error) {
    const repaired = await repairJson(response, config);
    return normalizeComponentPlan(JSON.parse(extractJsonObject(repaired)), markdown, logo);
  }
}
function deckFromComponentPlan(plan, logo) {
  return {
    deck: { size: "16x9", theme: "simple", brand: { ...plan.brand, logo } },
    slides: plan.slides.map((slide) => slideFromComponentPlan(slide, logo))
  };
}
function slideFromComponentPlan(plan, logo) {
  const contentChildren = plan.children.map((child, index) => expandAgentNode(plan.id, child, `${plan.id}.content.${index + 1}`, logo));
  const hasContentArea = contentChildren.some((child) => child.area === "content");
  return {
    id: plan.id,
    layout: "title-and-content",
    dom: {
      id: `${plan.id}.root`,
      type: "slide",
      background: "background",
      children: [
        {
          id: `${plan.id}.title`,
          type: "text",
          text: plan.title,
          style: "slide-title",
          align: "left"
        },
        ...hasContentArea ? contentChildren : [{
          id: `${plan.id}.content`,
          type: "stack",
          area: "content",
          direction: "vertical",
          gap: 0.35,
          children: contentChildren
        }]
      ]
    }
  };
}
function agentNodeComponentName(node) {
  if (node.type === "component")
    return String(node.component || "");
  if (node.type === "metric-card" || node.type === "step-card" || node.type === "comparison-card" || node.type === "callout")
    return node.type;
  return "";
}
function expandAgentNode(slideId, node, fallbackId, logo) {
  const componentName = agentNodeComponentName(node);
  if (componentName)
    return expandComponentNode(slideId, node, componentName, fallbackId, logo);
  const children = "children" in node && Array.isArray(node.children) ? node.children.map((child, index) => expandAgentNode(slideId, child, `${fallbackId}.${index + 1}`, logo)) : void 0;
  const { children: _children, ...fields } = node;
  return {
    ...sanitizeFields(fields),
    id: scopedId(slideId, node.id || fallbackId),
    type: node.type,
    children
  };
}
function expandComponentNode(slideId, node, componentName, fallbackId, _logo) {
  const id = scopedId(slideId, node.id || fallbackId);
  const localId = id.startsWith(`${slideId}.`) ? id.slice(slideId.length + 1) : id;
  if (componentName === "metric-card") {
    const unit = stringValue2(node.unit, "");
    return mergeRootFields(node, { ...metricCard(slideId, localId, `${stringValue2(node.value, "")}${unit}`, stringValue2(node.label, "")), id });
  }
  if (componentName === "step-card") {
    return mergeRootFields(node, { ...stepCard(slideId, localId, stringValue2(node.step, stringValue2(node.number, "")), stringValue2(node.title, stringValue2(node.label, "")), stringValue2(node.body, stringValue2(node.description, stringValue2(node.status, stringValue2(node.subtitle, stringArray2(node.steps).join("\n")))))), id });
  }
  if (componentName === "comparison-card") {
    return mergeRootFields(node, { ...comparisonCard(slideId, localId, stringValue2(node.title, ""), comparisonPoints2(node).slice(0, 5)), id });
  }
  return mergeRootFields(node, { ...insightCallout(slideId, localId, stringValue2(node.text, "")), id });
}
async function callComponentAgent(markdown, config) {
  const response = await fetch(`${normalizeAnthropicBaseURL(config.baseURL)}/v1/messages`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": config.apiKey,
      "anthropic-version": "2023-06-01"
    },
    body: JSON.stringify({
      model: config.model,
      max_tokens: config.maxTokens ?? 12e3,
      system: componentAgentPrompt(),
      messages: [{ role: "user", content: `\u8BF7\u6839\u636E\u4E0B\u9762 markdown \u751F\u6210 SlideML2 component deck JSON\u3002

${markdown}` }],
      stream: false
    })
  });
  if (!response.ok)
    throw new Error(`Component agent failed ${response.status}: ${await response.text()}`);
  const json = await response.json();
  const text = json.content?.map((part) => part.text || "").join("\n").trim();
  if (!text)
    throw new Error("Component agent returned empty content");
  return text;
}
async function repairJson(broken, config) {
  const response = await fetch(`${normalizeAnthropicBaseURL(config.baseURL)}/v1/messages`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": config.apiKey,
      "anthropic-version": "2023-06-01"
    },
    body: JSON.stringify({
      model: config.model,
      max_tokens: Math.min(config.maxTokens ?? 6e3, 6e3),
      system: "\u4F60\u662F JSON \u4FEE\u590D\u5668\u3002\u53EA\u8F93\u51FA\u4FEE\u590D\u540E\u7684 JSON\uFF0C\u4E0D\u8981\u89E3\u91CA\uFF0C\u4E0D\u8981 markdown \u4EE3\u7801\u5757\u3002",
      messages: [{ role: "user", content: `\u4FEE\u590D\u4E0B\u9762\u7684 SlideML2 JSON\u3002\u4FDD\u6301\u539F\u6709\u5185\u5BB9\uFF0C\u5220\u9664\u65E0\u6CD5\u4FEE\u590D\u7684\u5C3E\u90E8\u4E0D\u5B8C\u6574\u5BF9\u8C61\u4E5F\u53EF\u4EE5\uFF0C\u4F46\u5FC5\u987B\u8F93\u51FA\u5408\u6CD5 JSON\u3002

${broken}` }],
      stream: false
    })
  });
  if (!response.ok)
    throw new Error(`Component JSON repair failed ${response.status}: ${await response.text()}`);
  const json = await response.json();
  const text = json.content?.map((part) => part.text || "").join("\n").trim();
  if (!text)
    throw new Error("Component JSON repair returned empty content");
  return text;
}
